import { useState, useEffect } from "react";
import MovieList from "./components/MovieList";
import { useWindowWidth } from "./useWindowWidth";
import "./App.css";

function App() {
  const width = useWindowWidth();
  const [movies, setMovies] = useState([]);
  const [loading, setLoading] = useState(false);
  const [searchTerm, setSearchTerm] = useState("");
  const [query, setQuery] = useState("");
  const [selectedMovie, setSelectedMovie] = useState(null);

  useEffect(() => {
    handleSearch("avengers", false);
  }, []);

  const handleSearch = (term = searchTerm, isUserSearch = true) => {
    if (typeof term !== "string" || term.trim() === "") return;
    if (isUserSearch) setQuery(term);
    setLoading(true);

    fetch(`https://www.omdbapi.com{term}&apikey=5328cf5d`)
      .then((res) => res.json())
      .then((data) => {
        if (data.Search) {
          const formattedMovies = data.Search.map((movie) => ({
            id: movie.imdbID,
            title: movie.Title,
            poster: movie.Poster !== "N/A" ? movie.Poster : "https://via.placeholder.com"
          }));
          setMovies(formattedMovies);
        } else {
          setMovies([]);
        }
      })
      .catch(() => setMovies([]))
      .finally(() => setLoading(false));
  };

  const handleDeleteMovie = (id) => {
    setMovies(movies.filter((movie) => movie.id !== id));
  };

  const handleUpdateMovie = (id, newTitle) => {
    setMovies(movies.map((movie) => (movie.id === id ? { ...movie, title: newTitle } : movie)));
  };

  return (
    <div className="app-container">
      <div className="hero">
        <nav className="navbar"><div className="logo">VELLUM</div></nav>
        <div className="hero-content">
          <h1>Unlimited movies, series and more</h1>
          <div className="search-box">
            <input
              type="text"
              placeholder="Search movie..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
            <button onClick={() => handleSearch()} className={width < 600 ? "btn-mobile" : "btn-desktop"}>
              {width < 600 ? "🔍" : "Search Movie"}
            </button>
          </div>
        </div>
      </div>

      <div className="content">
        <h2 className="section-title">
          {query ? `Search Results for: "${query}"` : "Trending Movies"}
        </h2>

        {loading ? (
          <div className="loader-container"><div className="loader"></div></div>
        ) : (
          <MovieList
            movies={movies}
            onDelete={handleDeleteMovie}
            onUpdate={handleUpdateMovie}
            onSelect={setSelectedMovie}
          />
        )}
      </div>

      {/* --- POPUP MODAL --- */}
      {selectedMovie && (
        <div className="modal-overlay" onClick={() => setSelectedMovie(null)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()}>
            <button className="close-btn" onClick={() => setSelectedMovie(null)}>×</button>
            <img src={selectedMovie.poster} alt={selectedMovie.title} />
            <div className="modal-info">
              <h2>{selectedMovie.title}</h2>
              <p>ID: {selectedMovie.id}</p>
              <p>Movie details would go here.</p>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default App;
